import{_ as t,o as e,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"页面","description":"","frontmatter":{},"headers":[],"relativePath":"guide/page/index.md","filePath":"guide/page/index.md"}'),d={name:"guide/page/index.md"};function i(n,a,s,l,h,c){return e(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="页面" tabindex="-1">页面 <a class="header-anchor" href="#页面" aria-label="Permalink to &quot;页面&quot;">​</a></h1><p>页面是由<strong>页面模板</strong>和<strong>页面配置内容</strong>组成的。通过不同的页面配置，页面模板可以渲染出不同的页面效果。这种设计模式将页面的结构（模板）与内容（配置）分离，使得同一套模板可以服务于多种业务场景，极大提高了代码复用率。</p><h2 id="页面组成" tabindex="-1">页面组成 <a class="header-anchor" href="#页面组成" aria-label="Permalink to &quot;页面组成&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>页面 = 页面模板 + 页面配置</span></span></code></pre></div><ul><li><strong>页面模板</strong>：定义页面的整体结构和布局，决定页面由哪些组件组成以及组件的排列方式。</li><li><strong>页面配置</strong>：定义页面的具体内容，包括组件的属性、数据源、交互行为等。</li></ul><h2 id="常用页面模板" tabindex="-1">常用页面模板 <a class="header-anchor" href="#常用页面模板" aria-label="Permalink to &quot;常用页面模板&quot;">​</a></h2><p>EPX-Frame 内置了多种常用页面模板，覆盖了常见的业务场景：</p><table tabindex="0"><thead><tr><th>模板名称</th><th>说明</th></tr></thead><tbody><tr><td><code>entity-add-page</code></td><td>对象新增页面</td></tr><tr><td><code>entity-list-page</code></td><td>对象列表页面</td></tr><tr><td><code>entity-tree-manage</code></td><td>对象管理页面</td></tr><tr><td><code>entity-list-find-page</code></td><td>对象查找页面</td></tr></tbody></table><h3 id="对象新增页面" tabindex="-1">对象新增页面 <a class="header-anchor" href="#对象新增页面" aria-label="Permalink to &quot;对象新增页面&quot;">​</a></h3><p>用于创建新的业务数据记录。页面通常由<strong>标题导航组件</strong>和<strong>新增编辑表单组件</strong>组成，提供表单填写、数据校验和提交功能。</p><h3 id="对象列表页面" tabindex="-1">对象列表页面 <a class="header-anchor" href="#对象列表页面" aria-label="Permalink to &quot;对象列表页面&quot;">​</a></h3><p>用于展示和管理业务数据列表。页面通常由<strong>标题导航组件</strong>和<strong>对象列表组件</strong>组成，支持数据查询、筛选、分页、新增、编辑、删除、导入导出等操作。</p><h3 id="对象管理页面" tabindex="-1">对象管理页面 <a class="header-anchor" href="#对象管理页面" aria-label="Permalink to &quot;对象管理页面&quot;">​</a></h3><p>用于以树形结构管理业务数据，适用于有层级关系的数据管理场景，如组织架构、分类管理等。</p><h3 id="对象查找页面" tabindex="-1">对象查找页面 <a class="header-anchor" href="#对象查找页面" aria-label="Permalink to &quot;对象查找页面&quot;">​</a></h3><p>用于在列表中选择一条或多条数据记录，常用于关联选择、数据引用等场景。该页面继承自对象列表组件，并重写了部分变量和方法。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/guide/page/template.html">页面模板</a> — 了解页面模板的开发方式</li><li><a href="/guide/component/">组件概述</a> — 了解页面中使用的组件</li></ul>',18)])])}const u=t(d,[["render",i]]);export{g as __pageData,u as default};
